import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../../prisma.service';
import {
  DocumentCategory,
  DocumentStatus,
  EntityType,
  Prisma,
} from '@prisma/client';
import { UploadDocumentDto } from './dto/upload-document.dto';
import { VerifyDocumentDto } from './dto/verify-document.dto';
import { MediaStorageService } from '../../common/services/media-storage.service';

@Injectable()
export class DocumentsService {
  constructor(
    private prisma: PrismaService,
    private readonly mediaStorage: MediaStorageService,
  ) {}

  async uploadFile(
    file: Express.Multer.File,
    uploadDto: UploadDocumentDto,
    userId: string,
  ) {
    if (!file) {
      throw new BadRequestException('File is required');
    }

    // Upload to Cloudinary
    const uploadResult = await this.mediaStorage.uploadBuffer({
      buffer: file.buffer,
      folder: `evzone-documents/${uploadDto.entityType.toLowerCase()}/${uploadDto.entityId}`,
      resourceType: 'auto',
      context: `uploadedBy=${userId}|entityType=${uploadDto.entityType}|entityId=${uploadDto.entityId}|category=${uploadDto.category}`,
    });

    // Create Document record in DB
    return this.prisma.document.create({
      data: {
        category: uploadDto.category as DocumentCategory,
        entityType: uploadDto.entityType as EntityType,
        entityId: uploadDto.entityId,
        fileName: file.originalname,
        fileUrl: uploadResult.url,
        fileType: uploadResult.format || 'unknown',
        fileSize: uploadResult.bytes,
        cloudinaryPublicId: uploadResult.publicId,
        uploadedBy: userId,
        isRequired: uploadDto.isRequired || false,
        metadata: this.parseMetadata(uploadDto.metadata),
        status: DocumentStatus.PENDING,
      },
    });
  }

  async findAll(entityType: string, entityId: string) {
    return this.prisma.document.findMany({
      where: {
        entityType: entityType as EntityType,
        entityId,
      },
      orderBy: {
        createdAt: 'desc',
      },
    });
  }

  async findOne(id: string) {
    return this.prisma.document.findUnique({
      where: { id },
    });
  }

  async verifyDocument(
    id: string,
    verifyDto: VerifyDocumentDto,
    verifierId: string,
  ) {
    return this.prisma.document.update({
      where: { id },
      data: {
        status: verifyDto.status as DocumentStatus,
        notes: verifyDto.notes,
        rejectionReason: verifyDto.rejectionReason,
        verifiedBy: verifierId,
        verifiedAt: new Date(),
      },
    });
  }

  async deleteDocument(id: string) {
    const doc = await this.prisma.document.findUnique({ where: { id } });
    await this.mediaStorage.delete(doc?.cloudinaryPublicId);
    return this.prisma.document.delete({ where: { id } });
  }

  private parseMetadata(
    metadata: string | undefined,
  ): Prisma.InputJsonValue | undefined {
    if (!metadata) {
      return undefined;
    }

    try {
      const parsed: unknown = JSON.parse(metadata);
      return parsed as Prisma.InputJsonValue;
    } catch {
      throw new BadRequestException('metadata must be valid JSON');
    }
  }
}

import { MailService } from './mail.service';

describe('MailService', () => {
  const configService = {
    get: jest.fn((key: string, fallback?: string) => {
      const values: Record<string, string> = {
        TWILIO_SENDGRID_FROM: 'EVzone <noreply@evzonecharging.com>',
      };
      return values[key] ?? fallback;
    }),
  };
  const submailService = {
    sendEmail: jest.fn(),
  };
  const twilioSendgridService = {
    sendEmail: jest.fn(),
  };
  const routingService = {
    resolveEmailRoute: jest.fn(),
  };

  const service = new MailService(
    configService as any,
    submailService as any,
    twilioSendgridService as any,
    routingService as any,
  );

  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('falls back from SendGrid to Submail outside China', async () => {
    routingService.resolveEmailRoute.mockResolvedValue({
      geoBucket: 'other',
      primary: 'twilio_sendgrid',
      fallback: 'submail',
    });
    twilioSendgridService.sendEmail.mockRejectedValue(
      new Error('sendgrid failure'),
    );
    submailService.sendEmail.mockResolvedValue({ status: 'success' });

    const result = await service.sendMail(
      'user@example.com',
      'Hello',
      '<p>x</p>',
    );

    expect(twilioSendgridService.sendEmail).toHaveBeenCalledTimes(1);
    expect(submailService.sendEmail).toHaveBeenCalledTimes(1);
    expect(result).toEqual({ status: 'success' });
  });

  it('does not fallback for China email when Submail fails', async () => {
    routingService.resolveEmailRoute.mockResolvedValue({
      geoBucket: 'china',
      primary: 'submail',
    });
    submailService.sendEmail.mockRejectedValue(new Error('submail failure'));

    await expect(
      service.sendMail('cn-user@example.com', 'Hello', '<p>x</p>'),
    ).rejects.toThrow('submail failure');
    expect(twilioSendgridService.sendEmail).not.toHaveBeenCalled();
  });
});

